proof:
intro x hx; simp_all +decide [ Set.mem_smul_set_iff_inv_smul_mem, sq ] ;
rcases hx with ⟨ y, z, hy, hz, rfl ⟩ ; simp_all +decide [ Set.mem_mul ] ;
-- By the axiom of choice, we can pick for each i a c_i in F i and an a_i in A i such that y_i * hy_i = c_i * a_i.
have h_choice : ∀ i, ∃ c_i ∈ F i, ∃ a_i ∈ A i, y i * hy i = c_i * a_i := by
  intro i; specialize hFS i; simp_all +decide [ Set.mul_subset_iff ] ;
  simpa [ eq_comm, Set.mem_mul ] using hFS _ ( z i ) _ ( hz i );
choose c hc a ha hca using h_choice; use c; aesop;

